INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-06050', 'social-worker', 'social-worker-moex-104-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '「雨是一種單調而耐聽的音樂，是室內樂，是室外樂；戶內聽聽，戶外聽聽；冷冷， 那音樂。雨是一種回憶的音樂，聽聽那冷雨，回憶江南的雨下得滿地是江湖，下在 橋上和船上，也下在四川，在秧田和蛙塘下肥了嘉陵江下濕布穀咕咕的啼聲。」 （余光中〈聽聽那冷雨〉）下列選項，何者最貼近上文中作者的心情？', '["少年聽雨歌樓上，紅燭昏羅帳", "壯年聽雨客舟中，江闊雲低，斷雁叫西風", "而今聽雨僧廬下，鬢已星星也", "悲歡離合總無情，一任階前點滴到天明"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "2d4eac078260", "answer_pdf_sha1": "67c7445f2eb1", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06051', 'social-worker', 'social-worker-moex-104-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '王鼎鈞《碎琉璃．序文》（節錄）：「琉璃是佛教神話裡的一種寶石，它當然是不 碎的。／人不可能擁有真正的琉璃，於是設法用礦石燒製，於是有晶瑩輝煌的琉璃 瓦。／琉璃瓦離「琉璃」很遠，「琉璃燈」離琉璃更遠。／至於「琉璃河」，日夜 流去的都是尋常淡水，那就離「琉璃」更遠了。／生活，我本來以為是琉璃，其實 是琉璃瓦。／生活，我本來以為是琉璃瓦，其實是玻璃。／生活，我本來以為是玻 璃，其實是一河閃爍的波光。／生活，我終於發覺它是琉璃，是碎了的琉璃。」作 者文中所要表達的人生體驗為何？', '["不是每個人都可以掌握自我、從容出入各類角色，甚至由事件中全身而退", "我們每個人能夠活在這個世界上，本身就是一項奇蹟，所以我們每一個人都是獨 一無二的傳奇主角", "在人們虛虛實實的交通中，不免感到迷惑，一切彷彿是真實，卻又那麼虛浮", "尋找答案的過程雖然不免酸楚，但卻也是一種成長，一種對生活的理解 閱讀下文，回答第19題至第20題： 如同智慧需從生活經驗裡提煉，一個人對家族歷史的興趣也必須等到青春烈焰燃盡 了，眼瞳裡沒了火苗，才能靜心尋找先人足跡。然而，一人、一家、一族歷史皆是時代 洪流之旁支，我沿著幽深的時光甬道洄溯，原以為會找到我的先祖    他年輕力壯，在 彼端等我，沒想到一攤開臺灣開發史，出了時光甬道，赫然看到成千上萬荷鋤戴笠，正 等待船隻欲尋找海外天堂的浪子。 他們面目黧黑，衣衫藍縷，眼睛裡閃著最後一絲希望。 他們生死未卜。 他們之中大部分成為各姓宗祠裡虔誠禮拜的「入臺開基祖」。 （摘錄自簡媜《天涯海角》）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "2d4eac078260", "answer_pdf_sha1": "67c7445f2eb1", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06052', 'social-worker', 'social-worker-moex-104-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '本段文字主要傳達的文意，下列選項何者錯誤？', '["古早臺灣，一人之生，往往建築在眾人的死亡上", "當我們追索自身的家族史，同時也鉤沉了其他氏族的歷史", "每一支姓氏遷徙的故事，都是整個族群共同記憶的一部分", "臺灣以她海域般的雅量匯合每一支氏族顛沛流離的故事合撰成一部大傳奇"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "2d4eac078260", "answer_pdf_sha1": "67c7445f2eb1", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06053', 'social-worker', 'social-worker-moex-104-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '根據上文，「出了時光甬道，赫然看到成千上萬荷鋤戴笠，正等待船隻欲尋找海外 天堂的浪子。他們面目黧黑，衣衫藍縷，眼睛裡閃著最後一絲希望」的文意判斷， 這一批「浪子」，指的是那一時期移民臺灣的漢人？', '["1949年隨國民政府渡海來臺的各省百姓", "1895年甲午戰爭失敗，因清廷割讓臺灣而移民來臺的百姓", "乾隆至嘉慶年間，因沿海天災鬧飢荒而渡海來臺開墾尋糧的百姓", "明末清初，受鄭氏父子號召攻打被荷蘭人殖民佔領的臺灣的官兵及百姓"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:32+00:00", "source_pdf_sha1": "2d4eac078260", "answer_pdf_sha1": "67c7445f2eb1", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06054', 'social-worker', 'social-worker-moex-104-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '下列各選項「」中的數詞，何者屬於「虛數」而並非實指？', '["心上總是「七上八下」，一會兒神飛色舞，一會兒肉跳心驚", "光陰彈指，「七七」之期已過，范舉人出門謝了孝", "你兩個「八兩半斤」，好一對人客和主人", "老夫有一末堂幼女，年方「二八」"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "97ccad9eea1c", "answer_pdf_sha1": "6128e0e82a63", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06055', 'social-worker', 'social-worker-moex-104-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '老王的印舖要開張，朋友送對聯慶賀，請問下列何者較適切？', '["胸中存灼見，眼底辨秋毫", "六書傳四海，一刻值千金", "刻刻催人資警醒，聲聲勸爾惜光陰", "翰墨圖書皆成鳳采，往來談笑盡是鴻儒"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "97ccad9eea1c", "answer_pdf_sha1": "6128e0e82a63", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06056', 'social-worker', 'social-worker-moex-104-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '蘇軾名句：「但願人長久，千里共嬋娟。」其中，「嬋娟」代表的意義與下列詩句 中「」內的詞語意義完全不相近的是那一個選項？', '["陽烏未出谷，「顧兔」半藏身。女媧戲黃土，團作愚下人", "閩國揚帆去，「蟾蜍」虧復團。秋風生渭水，落葉滿長安", "可憐「瑤臺」樹，灼灼佳人姿。碧華映朱實，攀折青春時", "殘夜露如雨，秋氣淒以分。牆西雲正黑，跕跕墮「金盆」"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "97ccad9eea1c", "answer_pdf_sha1": "6128e0e82a63", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06057', 'social-worker', 'social-worker-moex-104-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '不敢入詩的 來入夢 夢是一條絲 穿梭那 不可能的 相逢  （夐虹〈夢〉） 有關本詩，下列敘述何者最正確？', '["詩歌可以穿越夢境", "夢境可以穿越古今", "夢境可以呈現詩歌怯於表達的情境", "夢境不可能幫我們達成不可預期的事情"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "97ccad9eea1c", "answer_pdf_sha1": "6128e0e82a63", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06058', 'social-worker', 'social-worker-moex-104-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '知榮知辱牢緘口。誰是誰非暗點頭。詩書叢裏且淹留。閑袖手。貧煞也風流。 （白樸〈〔中呂〕陽春曲．知幾〉）下列選項何者與上文意旨無關？', '["靜觀世事，擊壤自安貧", "曲肱枕之，詩書常共讀", "皮裏陽秋，瀟灑風塵外", "偎紅倚翠，浮名換酌唱"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "97ccad9eea1c", "answer_pdf_sha1": "6128e0e82a63", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06059', 'social-worker', 'social-worker-moex-104-9a386a01', 'sub-social-worker-07', NULL, 'single_choice', '詹姆斯．傅瑞《超棒小說這樣寫》說道：「在故事裡『眼前』的衝突還沒有升高時， 有些作者就開始憶往，也不管往昔的衝突對於故事的『現在』有沒有影響，因為那 是過去的事，作者用這種方式放鬆。」下列選項何者非作者的主張？', '["「情節」設置必要合理", "「回顧」技巧不可濫用", "「衝突」高潮得視條件", "「時間」安排需有彈性"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:33+00:00", "source_pdf_sha1": "97ccad9eea1c", "answer_pdf_sha1": "6128e0e82a63", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "1102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
